import{scaleLinear as d3ScaleLinear}from"d3-scale";import{builtInEvaluate,intervalEvaluate}from"./evaluate-datum.js";const width=200,height=100,nSamples=100,config={options:{xAxis:{type:"linear"}},emit:()=>{},meta:{xScale:d3ScaleLinear().domain([-5,5]).range([0,width]),yScale:d3ScaleLinear().domain([-5,5]).range([height,0])}};describe("evaluate",()=>{it("should eval linear functions (builtin)",()=>{var e={fn:"x^2",sampler:"builtIn",fnType:"linear",nSamples:nSamples},e=builtInEvaluate(config,e);expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(1),expect(e[0].length).toEqual(nSamples),expect(e[0][0]).toEqual([-5,25]),expect(e[0][nSamples-1]).toEqual([5,25]),expect(e[0][nSamples/2][0]).toBeCloseTo(0,0),expect(e[0][nSamples/2][1]).toBeCloseTo(0,0)}),it("should eval linear functions (interval)",()=>{var e={fn:"x^2",sampler:"interval",fnType:"linear",nSamples:nSamples},e=intervalEvaluate(config,e);expect(e.length).toEqual(1),expect(e[0][0][0].lo<=-5&&-5<=e[0][0][0].hi).toBe(!0),expect(e[0][0][1].lo<=25&&25<=e[0][0][1].hi).toBe(!0),expect(e[0][nSamples-2][0].lo<=5&&5<=e[0][nSamples-2][0].hi).toBe(!0),expect(e[0][nSamples-2][1].lo<=25&&25<=e[0][nSamples-2][1].hi).toBe(!0),expect(e[0][nSamples/2][0].lo).toBeCloseTo(0,0),expect(e[0][nSamples/2][0].hi).toBeCloseTo(0,0),expect(e[0][nSamples/2][1].lo).toBeCloseTo(0,0),expect(e[0][nSamples/2][1].hi).toBeCloseTo(0,0)})});